<span class="line">        <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;具体类B - 操作2&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
